import requests
from typing import Dict, Any, Optional

def fetch_url_content(url: str, headers: Optional[Dict[str, str]] = None, timeout: int = 30) -> Dict[str, Any]:
    """
    Fetches and displays the content of a URL provided by the user.
    
    Args:
        url (str): The URL to fetch content from
        headers (dict, optional): HTTP headers to include in the request
        timeout (int): Request timeout in seconds
        
    Returns:
        dict: Response data including status, content, and headers
    """
    try:
        response = requests.get(
            url,
            headers=headers,
            timeout=timeout
        )
        response.raise_for_status()
        
        return {
            'status': 'success',
            'url': url,
            'status_code': response.status_code,
            'content': response.text,
            'headers': dict(response.headers),
            'encoding': response.encoding
        }
        
    except requests.exceptions.RequestException as e:
        return {
            'status': 'error',
            'url': url,
            'error': str(e),
            'status_code': getattr(e.response, 'status_code', None) if hasattr(e, 'response') else None
        }

def process_webhook_request(webhook_data: Dict[str, Any]) -> Dict[str, Any]:
    """
    Process webhook requests from partner APIs.
    
    Args:
        webhook_data (dict): Data from the webhook request
        
    Returns:
        dict: Processed result
    """
    # Extract URL from webhook data
    url = webhook_data.get('url')
    headers = webhook_data.get('headers', {})
    
    if not url:
        return {
            'status': 'error',
            'message': 'No URL provided in webhook data'
        }
    
    # Fetch content from URL
    result = fetch_url_content(url, headers)
    
    # Add webhook metadata to result
    result['webhook_id'] = webhook_data.get('webhook_id')
    result['integration_type'] = webhook_data.get('integration_type')
    
    return result